=<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
  <title>Content Approved — FM Matrix</title>
  <link href="https://fonts.googleapis.com/css2?family=DM+Sans:ital,wght@0,300;0,400;0,500;0,600;1,400&family=DM+Mono:wght@400;500&display=swap" rel="stylesheet"/>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

    :root {
      --bg:        #F5F4F0;
      --surface:   #FFFFFF;
      --surface2:  #F9F8F5;
      --border:    rgba(0,0,0,0.08);
      --text-1:    #1A1916;
      --text-2:    #5C5A54;
      --text-3:    #9B9890;
      --green-bg:  #E4F5EC;
      --green-bd:  #34A85A;
      --green-tx:  #1A5E34;
      --radius-md: 10px;
      --radius-lg: 16px;
    }

    body {
      font-family: 'DM Sans', sans-serif;
      background: var(--bg);
      min-height: 100vh;
      display: flex;
      align-items: flex-start;
      justify-content: center;
      padding: 40px 16px;
      color: var(--text-1);
    }

    .wrapper { width: 100%; max-width: 780px; }

    .topbar {
      display: flex;
      align-items: center;
      justify-content: space-between;
      margin-bottom: 20px;
    }
    .topbar-brand {
      font-size: 13px;
      font-weight: 500;
      color: var(--text-3);
      letter-spacing: 0.04em;
      text-transform: uppercase;
    }
    .topbar-brand span { color: var(--text-1); }

    .card {
      background: var(--surface);
      border: 1px solid var(--border);
      border-radius: var(--radius-lg);
      overflow: hidden;
      box-shadow: 0 2px 12px rgba(0,0,0,0.05);
      animation: slideUp 0.6s ease-out;
    }

    .card-header {
      padding: 28px;
      text-align: center;
      border-bottom: 1px solid var(--border);
    }

    .status-badge {
      display: inline-flex;
      align-items: center;
      gap: 10px;
      background: var(--green-bg);
      border: 1px solid var(--green-bd);
      color: var(--green-tx);
      padding: 12px 20px;
      border-radius: 24px;
      font-size: 15px;
      font-weight: 500;
      margin-bottom: 16px;
      animation: slideDown 0.5s ease-out 0.1s both;
    }

    .status-badge svg {
      width: 18px;
      height: 18px;
      stroke: currentColor;
      fill: none;
      stroke-width: 2;
      stroke-linecap: round;
      stroke-linejoin: round;
    }

    .subject {
      font-size: 24px;
      font-weight: 500;
      line-height: 1.4;
      color: var(--text-1);
    }

    .card-body {
      padding: 28px;
    }

    .section-label {
      font-size: 11px;
      font-weight: 600;
      color: var(--text-3);
      letter-spacing: 0.08em;
      text-transform: uppercase;
      margin-bottom: 12px;
      margin-top: 24px;
    }

    .section-label:first-child {
      margin-top: 0;
    }

    .content-block {
      background: var(--surface2);
      border: 1px solid var(--border);
      border-radius: var(--radius-md);
      padding: 22px 24px;
      margin-bottom: 20px;
      animation: slideUp 0.6s ease-out 0.2s both;
    }

    .content-block p {
      font-size: 15px;
      line-height: 1.8;
      color: var(--text-1);
      white-space: pre-wrap;
      word-wrap: break-word;
    }

    .meta-grid {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 16px;
      animation: slideUp 0.6s ease-out 0.3s both;
    }

    .meta-item {
      background: var(--surface2);
      border: 1px solid var(--border);
      border-radius: var(--radius-md);
      padding: 16px 18px;
    }

    .meta-label {
      font-size: 11px;
      font-weight: 600;
      color: var(--text-3);
      letter-spacing: 0.08em;
      text-transform: uppercase;
      display: block;
      margin-bottom: 8px;
    }

    .meta-value {
      font-size: 15px;
      font-weight: 500;
      color: var(--text-1);
    }

    .card-footer {
      padding: 16px 28px;
      border-top: 1px solid var(--border);
      background: var(--surface2);
      text-align: center;
      font-size: 12px;
      color: var(--text-3);
      animation: slideUp 0.6s ease-out 0.4s both;
    }

    @keyframes slideUp {
      from {
        opacity: 0;
        transform: translateY(20px);
      }
      to {
        opacity: 1;
        transform: translateY(0);
      }
    }

    @keyframes slideDown {
      from {
        opacity: 0;
        transform: translateY(-20px);
      }
      to {
        opacity: 1;
        transform: translateY(0);
      }
    }

    @media (max-width: 520px) {
      .subject { font-size: 20px; }
      .card-header, .card-body { padding: 20px 18px; }
      .meta-grid {
        grid-template-columns: 1fr;
      }
    }
  </style>
</head>
<body>
<div class="wrapper">
  <div class="card">

    <!-- Header -->
    <div class="card-header">
      <div class="status-badge">
        <svg viewBox="0 0 16 16">
          <path d="M3 8L6.5 11.5L13 5"/>
        </svg>
        Content Approved
      </div>
      <h1 class="subject">DFID-{{ $('Update row in sheet1').item.json.Draft_ID }}</h1>
    </div>

    <!-- Body -->
    <div class="card-body">

      <div class="section-label">Approved content</div>
      <div class="content-block">
        <p>{{ $('Update row in sheet1').item.json.Post_Content }}</p>
      </div>

      <div class="section-label">Approval details</div>
      <div class="meta-grid">
        <div class="meta-item">
          <span class="meta-label">Draft ID</span>
          <div class="meta-value">{{ $('Update row in sheet1').item.json.Draft_ID }}</div>
        </div>
        <div class="meta-item">
          <span class="meta-label">Approved by</span>
          <div class="meta-value" id="approverName">{{ $('Update row in sheet1').item.json.Action_Taken_by }}</div>
        </div>
      </div>

    </div>

    <!-- Footer -->
    <div class="card-footer">
      ✓ Review completed • Ready for publication
    </div>

  </div>

</div>

<script>
// Format email(s) to name(s) - handles single or multiple emails
window.addEventListener('DOMContentLoaded', function(){
  const emailEl = document.getElementById('approverName');
  const emailText = emailEl.textContent.trim();

  if(emailText && emailText.includes('@')){
    // Handle multiple emails separated by commas
    const names = emailText
      .split(',')
      .map(email => {
        email = email.trim();
        // Get part before @
        let name = email.split('@')[0];
        // Split by dots and capitalize each part
        return name
          .split('.')
          .map(part => part.charAt(0).toUpperCase() + part.slice(1))
          .join(' ');
      })
      .join(', ');

    emailEl.textContent = names;
  }
});
</script>
</body>
</html>

